import React from 'react';
import ReactDOM from 'react-dom';


function Home() {
    const movies = {
        moviesName : ["Kantara","Ramayana","Rocketry", "Dangal"]
    }
    return ( 
        <>
            <h2>Welcome Movie World !</h2>
            <p>This are list of our movie :</p>
            <ol>
                {this.movies.moviesName.map(moviename => { <li key={moviename}>moviename</li>})}
            </ol>
        </>
     );
}

export default Home;
